/**
 * QR Code Generator - Minimal inline implementation for Chrome Extension
 * Based on qrcode-generator by Kazuhiko Arase (MIT License)
 * Generates QR codes as data URLs for display in popup.
 */
var QRCode = (function() {
  // QR Code Model 2 implementation
  var PAD0 = 0xEC, PAD1 = 0x11;

  // Error correction levels
  var ECL = { L: 1, M: 0, Q: 3, H: 2 };

  // Number of error correction codewords per block for each version/ecl
  var EC_CODEWORDS_TABLE = [
    // V1-V10 for ECL M (sufficient for our use case)
    [null],
    [null, 10, 16, 26, 18],  // V1: L=7, M=10, Q=13, H=17
    [null, 16, 28, 44, 28],
    [null, 26, 44, 70, 44],
    [null, 18, 32, 50, 32],
    [null, 20, 36, 54, 36],
    [null, 24, 43, 58, 43],
    [null, 30, 50, 64, 50],
    [null, 18, 36, 55, 36],
    [null, 20, 43, 65, 43],
    [null, 24, 50, 75, 50],
  ];

  function generateQRDataURL(text, size) {
    size = size || 256;

    // Use a canvas-based approach via the built-in QR generation
    var canvas = document.createElement('canvas');
    canvas.width = size;
    canvas.height = size;
    var ctx = canvas.getContext('2d');

    // Simple QR encoding using the QR code algorithm
    var modules = generateQRModules(text);
    if (!modules) return null;

    var moduleCount = modules.length;
    var cellSize = size / moduleCount;

    ctx.fillStyle = '#ffffff';
    ctx.fillRect(0, 0, size, size);

    ctx.fillStyle = '#000000';
    for (var r = 0; r < moduleCount; r++) {
      for (var c = 0; c < moduleCount; c++) {
        if (modules[r][c]) {
          ctx.fillRect(c * cellSize, r * cellSize, cellSize + 0.5, cellSize + 0.5);
        }
      }
    }

    return canvas.toDataURL('image/png');
  }

  // Minimal QR code generation - Version 1-10, byte mode, ECL M
  function generateQRModules(text) {
    var data = [];
    for (var i = 0; i < text.length; i++) {
      var code = text.charCodeAt(i);
      if (code < 128) {
        data.push(code);
      } else if (code < 2048) {
        data.push(0xC0 | (code >> 6));
        data.push(0x80 | (code & 0x3F));
      } else {
        data.push(0xE0 | (code >> 12));
        data.push(0x80 | ((code >> 6) & 0x3F));
        data.push(0x80 | (code & 0x3F));
      }
    }

    // Determine version (1-40) based on data capacity in byte mode, ECL M
    var capacities = [0, 14, 26, 42, 62, 84, 106, 122, 152, 180, 213,
                      251, 287, 331, 362, 412, 450, 504, 560, 624, 666];
    var version = 0;
    for (var v = 1; v <= 20; v++) {
      if (data.length <= capacities[v]) { version = v; break; }
    }
    if (version === 0) return null; // too much data

    var moduleCount = version * 4 + 17;
    var modules = [];
    for (var r = 0; r < moduleCount; r++) {
      modules[r] = [];
      for (var c = 0; c < moduleCount; c++) {
        modules[r][c] = null;
      }
    }

    // Place finder patterns
    placeFinder(modules, 0, 0);
    placeFinder(modules, moduleCount - 7, 0);
    placeFinder(modules, 0, moduleCount - 7);

    // Place timing patterns
    for (var i = 8; i < moduleCount - 8; i++) {
      if (modules[6][i] === null) modules[6][i] = (i % 2 === 0);
      if (modules[i][6] === null) modules[i][6] = (i % 2 === 0);
    }

    // Place alignment patterns (version >= 2)
    if (version >= 2) {
      var positions = getAlignmentPositions(version);
      for (var i = 0; i < positions.length; i++) {
        for (var j = 0; j < positions.length; j++) {
          var row = positions[i], col = positions[j];
          if (modules[row][col] !== null) continue;
          placeAlignment(modules, row, col);
        }
      }
    }

    // Reserve format info areas
    reserveFormatInfo(modules, moduleCount);

    // Version info (version >= 7)
    if (version >= 7) {
      placeVersionInfo(modules, version, moduleCount);
    }

    // Encode data
    var encoded = encodeData(data, version);

    // Place data bits
    placeData(modules, encoded, moduleCount);

    // Apply mask (mask 0 for simplicity)
    applyMask(modules, moduleCount, 0);

    // Place format info
    placeFormatInfo(modules, moduleCount, 0, 0); // ECL M = 0, mask 0

    return modules;
  }

  function placeFinder(modules, row, col) {
    for (var r = -1; r <= 7; r++) {
      for (var c = -1; c <= 7; c++) {
        var mr = row + r, mc = col + c;
        if (mr < 0 || mr >= modules.length || mc < 0 || mc >= modules.length) continue;
        if ((r >= 0 && r <= 6 && (c === 0 || c === 6)) ||
            (c >= 0 && c <= 6 && (r === 0 || r === 6)) ||
            (r >= 2 && r <= 4 && c >= 2 && c <= 4)) {
          modules[mr][mc] = true;
        } else {
          modules[mr][mc] = false;
        }
      }
    }
  }

  function placeAlignment(modules, centerRow, centerCol) {
    for (var r = -2; r <= 2; r++) {
      for (var c = -2; c <= 2; c++) {
        var mr = centerRow + r, mc = centerCol + c;
        if (mr < 0 || mr >= modules.length || mc < 0 || mc >= modules.length) continue;
        if (Math.abs(r) === 2 || Math.abs(c) === 2 || (r === 0 && c === 0)) {
          modules[mr][mc] = true;
        } else {
          modules[mr][mc] = false;
        }
      }
    }
  }

  function getAlignmentPositions(version) {
    if (version === 1) return [];
    var positions = [6];
    var last = version * 4 + 10;
    var count = Math.floor(version / 7) + 2;
    var step = (count === 2) ? 0 : Math.ceil((last - 6) / (count - 1));
    if (step % 2 !== 0) step++;
    for (var i = count - 1; i > 0; i--) {
      positions.unshift(last - (count - 1 - i) * step);
    }
    positions[0] = 6;
    // Remove duplicates and sort
    var unique = [];
    for (var i = 0; i < positions.length; i++) {
      if (unique.indexOf(positions[i]) === -1) unique.push(positions[i]);
    }
    unique.sort(function(a, b) { return a - b; });
    return unique;
  }

  function reserveFormatInfo(modules, size) {
    // Row 8, cols 0-8 and size-8 to size-1
    for (var c = 0; c <= 8; c++) {
      if (modules[8][c] === null) modules[8][c] = false;
    }
    for (var c = size - 8; c < size; c++) {
      if (modules[8][c] === null) modules[8][c] = false;
    }
    // Col 8, rows 0-8 and size-8 to size-1
    for (var r = 0; r <= 8; r++) {
      if (modules[r][8] === null) modules[r][8] = false;
    }
    for (var r = size - 7; r < size; r++) {
      if (modules[r][8] === null) modules[r][8] = false;
    }
    // Dark module
    modules[size - 8][8] = true;
  }

  function placeVersionInfo(modules, version, size) {
    var bits = getVersionBits(version);
    for (var i = 0; i < 18; i++) {
      var bit = (bits >> i) & 1;
      var r = Math.floor(i / 3);
      var c = size - 11 + (i % 3);
      modules[r][c] = !!bit;
      modules[c][r] = !!bit;
    }
  }

  function getVersionBits(version) {
    var d = version << 12;
    var poly = 0x1F25; // Generator polynomial for version info
    while (getBitLength(d) - getBitLength(poly) >= 0) {
      d ^= poly << (getBitLength(d) - getBitLength(poly));
    }
    return (version << 12) | d;
  }

  function getBitLength(n) {
    var len = 0;
    while (n > 0) { len++; n >>= 1; }
    return len;
  }

  function encodeData(data, version) {
    // Total data codewords for version (ECL M)
    var totalCodewords = getTotalCodewords(version);
    var ecCodewords = getECCodewords(version);
    var dataCodewords = totalCodewords - ecCodewords;

    // Build bit stream: mode indicator (0100 = byte) + char count + data
    var bits = [];
    // Mode: byte = 0100
    pushBits(bits, 4, 4);
    // Char count indicator length depends on version
    var ccBits = version <= 9 ? 8 : 16;
    pushBits(bits, data.length, ccBits);
    // Data bytes
    for (var i = 0; i < data.length; i++) {
      pushBits(bits, data[i], 8);
    }
    // Terminator
    var totalBits = dataCodewords * 8;
    var termLen = Math.min(4, totalBits - bits.length);
    pushBits(bits, 0, termLen);
    // Byte align
    while (bits.length % 8 !== 0) bits.push(0);
    // Pad codewords
    while (bits.length < totalBits) {
      pushBits(bits, PAD0, 8);
      if (bits.length < totalBits) pushBits(bits, PAD1, 8);
    }

    // Convert to byte array
    var codewords = [];
    for (var i = 0; i < bits.length; i += 8) {
      var byte = 0;
      for (var j = 0; j < 8; j++) {
        byte = (byte << 1) | (bits[i + j] || 0);
      }
      codewords.push(byte);
    }

    // Generate EC codewords (simplified Reed-Solomon)
    var ecBytes = generateEC(codewords.slice(0, dataCodewords), ecCodewords);

    // Interleave (single block for small versions)
    var result = [];
    for (var i = 0; i < dataCodewords; i++) result.push(codewords[i]);
    for (var i = 0; i < ecBytes.length; i++) result.push(ecBytes[i]);

    return result;
  }

  function pushBits(arr, value, length) {
    for (var i = length - 1; i >= 0; i--) {
      arr.push((value >> i) & 1);
    }
  }

  function getTotalCodewords(version) {
    var sizes = [0, 26, 44, 70, 100, 134, 172, 196, 242, 292, 346,
                 404, 466, 532, 581, 655, 733, 815, 901, 991, 1085];
    return sizes[version] || 0;
  }

  function getECCodewords(version) {
    var ecw = [0, 10, 16, 26, 18, 24, 16, 18, 22, 22, 26,
               30, 22, 22, 24, 24, 28, 28, 26, 26, 26];
    return ecw[version] || 0;
  }

  // Reed-Solomon error correction using GF(256)
  var GF_EXP = new Array(256);
  var GF_LOG = new Array(256);
  (function initGF() {
    var x = 1;
    for (var i = 0; i < 255; i++) {
      GF_EXP[i] = x;
      GF_LOG[x] = i;
      x <<= 1;
      if (x >= 256) x ^= 0x11D;
    }
    GF_EXP[255] = GF_EXP[0];
  })();

  function gfMul(a, b) {
    if (a === 0 || b === 0) return 0;
    return GF_EXP[(GF_LOG[a] + GF_LOG[b]) % 255];
  }

  function generateEC(data, ecLength) {
    // Build generator polynomial
    var gen = [1];
    for (var i = 0; i < ecLength; i++) {
      var newGen = new Array(gen.length + 1).fill(0);
      for (var j = 0; j < gen.length; j++) {
        newGen[j] ^= gen[j];
        newGen[j + 1] ^= gfMul(gen[j], GF_EXP[i]);
      }
      gen = newGen;
    }

    // Polynomial division
    var msg = data.slice();
    for (var i = 0; i < ecLength; i++) msg.push(0);

    for (var i = 0; i < data.length; i++) {
      var coef = msg[i];
      if (coef !== 0) {
        for (var j = 1; j < gen.length; j++) {
          msg[i + j] ^= gfMul(gen[j], coef);
        }
      }
    }

    return msg.slice(data.length);
  }

  function placeData(modules, data, size) {
    var bitIndex = 0;
    var totalBits = data.length * 8;

    // Data is placed in a zigzag pattern from bottom-right
    var col = size - 1;
    var direction = -1; // -1 = up, 1 = down

    while (col > 0) {
      if (col === 6) col--; // Skip timing column

      for (var count = 0; count < size; count++) {
        var row = direction === -1 ? size - 1 - count : count;

        for (var dc = 0; dc <= 1; dc++) {
          var c = col - dc;
          if (modules[row][c] !== null) continue; // Already placed (pattern area)

          var dark = false;
          if (bitIndex < totalBits) {
            var byteIndex = Math.floor(bitIndex / 8);
            var bitPos = 7 - (bitIndex % 8);
            dark = ((data[byteIndex] >> bitPos) & 1) === 1;
            bitIndex++;
          }
          modules[row][c] = dark;
        }
      }

      col -= 2;
      direction = -direction;
    }
  }

  function applyMask(modules, size, maskPattern) {
    for (var r = 0; r < size; r++) {
      for (var c = 0; c < size; c++) {
        if (isPatternArea(r, c, size)) continue;
        var mask = false;
        switch (maskPattern) {
          case 0: mask = (r + c) % 2 === 0; break;
          case 1: mask = r % 2 === 0; break;
          case 2: mask = c % 3 === 0; break;
          case 3: mask = (r + c) % 3 === 0; break;
          case 4: mask = (Math.floor(r / 2) + Math.floor(c / 3)) % 2 === 0; break;
          case 5: mask = ((r * c) % 2) + ((r * c) % 3) === 0; break;
          case 6: mask = (((r * c) % 2) + ((r * c) % 3)) % 2 === 0; break;
          case 7: mask = (((r + c) % 2) + ((r * c) % 3)) % 2 === 0; break;
        }
        if (mask) modules[r][c] = !modules[r][c];
      }
    }
  }

  function isPatternArea(row, col, size) {
    // Finder patterns + separators
    if (row <= 8 && col <= 8) return true;
    if (row <= 8 && col >= size - 8) return true;
    if (row >= size - 8 && col <= 8) return true;
    // Timing patterns
    if (row === 6 || col === 6) return true;
    // Format info
    if (row === 8 || col === 8) return true;
    return false;
  }

  function placeFormatInfo(modules, size, ecLevel, maskPattern) {
    // ECL M = 00, mask 0 = 000 -> format bits = 00000
    // After BCH and XOR mask: pre-computed for common cases
    var FORMAT_BITS = [
      // ECL M (00), masks 0-7
      0x5412, 0x5125, 0x5E7C, 0x5B4B, 0x45F9, 0x40CE, 0x4F97, 0x4AA0,
    ];

    var bits = FORMAT_BITS[maskPattern] || FORMAT_BITS[0];

    // Place around top-left finder
    for (var i = 0; i <= 5; i++) {
      modules[8][i] = !!((bits >> (14 - i)) & 1);
    }
    modules[8][7] = !!((bits >> 8) & 1);
    modules[8][8] = !!((bits >> 7) & 1);
    modules[7][8] = !!((bits >> 6) & 1);
    for (var i = 0; i <= 5; i++) {
      modules[5 - i][8] = !!((bits >> (i + 9)) & 1);
    }

    // Place along bottom-left and top-right
    for (var i = 0; i <= 7; i++) {
      modules[size - 1 - i][8] = !!((bits >> i) & 1);
    }
    for (var i = 0; i <= 7; i++) {
      modules[8][size - 8 + i] = !!((bits >> (14 - 8 - i)) & 1);
    }
  }

  return { toDataURL: generateQRDataURL };
})();
